	private static Path generationDataPath(Path tempDir, long generation) {
		return tempDir.resolve("join-estimator/omni-witness-a-" + Long.toUnsignedString(generation) + ".dat");
	}

	private static long[] sortedWitnessHashes(int count) {
		Long[] boxed = new Long[count];
		for (int i = 0; i < count; i++) {
			boxed[i] = OmniJoinEstimator.stableHash("event:" + i);
		}
		Arrays.sort(boxed, Long::compareUnsigned);
		long[] hashes = new long[count];
		for (int i = 0; i < count; i++) {
			hashes[i] = boxed[i];
		}
		return hashes;
	}
